parameters.jsCode:
const response = $input.item.json;
let analysisText = '';
let analysisData = {};

try {
  analysisText = response.candidates[0].content.parts[0].text;

  // Try to extract JSON from the response
  const jsonMatch = analysisText.match(/```json([\s\S]*?)```/) || analysisText.match(/{[\s\S]*}/);
  if (jsonMatch) {
    const jsonStr = jsonMatch[1] ? jsonMatch[1].trim() : jsonMatch[0];
    analysisData = JSON.parse(jsonStr);
  } else {
    // If no JSON found, structure the raw text
    analysisData = {
      raw_analysis: analysisText,
      color_palette: 'See raw analysis',
      pattern_style: 'See raw analysis',
      mood: 'See raw analysis',
      ideal_locations: ['See raw analysis'],
      room_types: ['See raw analysis'],
      complementary_decor: ['See raw analysis']
    };
  }
} catch(e) {
  analysisData = {
    error: 'Failed to parse AI response',
    raw_text: analysisText,
    parse_error: e.message
  };
}

const previousData = $input.item.json;

return {
  json: {
    carpetId: previousData.carpetId || $('Extract Image Data').item.json.carpetId,
    carpetName: previousData.carpetName || $('Extract Image Data').item.json.carpetName,
    submittedBy: previousData.submittedBy || $('Extract Image Data').item.json.submittedBy,
    uploadTimestamp: previousData.uploadTimestamp || $('Extract Image Data').item.json.uploadTimestamp,
    colorPalette: analysisData.color_palette || analysisData.colorPalette || 'Not identified',
    patternStyle: analysisData.pattern_style || analysisData.patternStyle || 'Not identified',
    texture: analysisData.texture || 'Not identified',
    mood: analysisData.mood || analysisData.ambiance || 'Not identified',
    idealLocations: Array.isArray(analysisData.ideal_locations || analysisData.idealLocations) 
      ? (analysisData.ideal_locations || analysisData.idealLocations).join(', ') 
      : JSON.stringify(analysisData.ideal_locations || analysisData.idealLocations || 'Not identified'),
    roomTypes: Array.isArray(analysisData.room_types || analysisData.roomTypes) 
      ? (analysisData.room_types || analysisData.roomTypes).join(', ') 
      : JSON.stringify(analysisData.room_types || analysisData.roomTypes || 'Not identified'),
    complementaryDecor: Array.isArray(analysisData.complementary_decor || analysisData.complementaryDecor) 
      ? (analysisData.complementary_decor || analysisData.complementaryDecor).join(', ') 
      : JSON.stringify(analysisData.complementary_decor || analysisData.complementaryDecor || 'Not identified'),
    fullAnalysis: JSON.stringify(analysisData),
    analysisStatus: 'completed',
    processedAt: new Date().toISOString()
  }
};

